import React, { useEffect, useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const biometricAuth = new ReactNativeBiometrics();

  useEffect(() => {
    checkAuthenticationStatus();
  }, []);

  const checkAuthenticationStatus = async () => {
    try {
      const authStatus = await AsyncStorage.getItem('authStatus');
      if (authStatus === 'true') {
        setIsAuthenticated(true);
      }
    } catch (error) {
      console.error('Error checking authentication status:', error);
    }
  };

  const authenticate = async () => {
    biometricAuth.isSensorAvailable().then((resultObject) => {
      const { available, reason } = resultObject;

      if (available && (reason === 'FaceID' || reason === 'TouchID')) {
        biometricAuth.simplePrompt({ promptMessage: 'Sign in with Face ID or Touch ID' })
          .then((resultObject) => {
            const { success } = resultObject;
            if (success) {
              setIsAuthenticated(true);
              storeAuthenticationStatus('true');
            }
          })
          .catch(() => {
            alert('Biometric authentication failed. Please try again.');
          });
      } else {
        // Fallback to password
        alert('Your device does not support Face ID or Touch ID. Please use a password instead.');
      }
    });
  };

  const storeAuthenticationStatus = async (status) => {
    try {
      await AsyncStorage.setItem('authStatus', status);
    } catch (error) {
      console.error('Error storing authentication status:', error);
    }
  };

  if (!isAuthenticated) {
    return (
      <View style={styles.container}>
        <Text>Please authenticate to continue.</Text>
        <Button title="Authenticate" onPress={authenticate} />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text>Welcome! You are authenticated.</Text>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
});

export default App;